import{_ as t,o as a,c as s,ag as n}from"./chunks/framework.eQLvDOR_.js";const g=JSON.parse('{"title":"Production-grade engineering skills for AI coding agents.md","description":"","frontmatter":{"title":"Production-grade engineering skills for AI coding agents.md","source":"unknown","clipped_at":"2026-04-06T00:00:00.000Z","category":"ADK_Agent_Skills","tags":["agent-skills","workflow","best-practices"],"status":"distilled","compiled":true},"headers":[],"relativePath":"library/ADK_Agent_Skills/ADK_Agent_Skills - Production-grade engineering skills for AI coding agents.md","filePath":"library/ADK_Agent_Skills/ADK_Agent_Skills - Production-grade engineering skills for AI coding agents.md","lastUpdated":null}'),i={name:"library/ADK_Agent_Skills/ADK_Agent_Skills - Production-grade engineering skills for AI coding agents.md"};function r(o,e,l,d,c,p){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="agent-skills" tabindex="-1">Agent Skills <a class="header-anchor" href="#agent-skills" aria-label="Permalink to &quot;Agent Skills&quot;">​</a></h1><p><strong>Production-grade engineering skills for AI coding agents.</strong></p><p>Skills encode the workflows, quality gates, and best practices that senior engineers use when building software. These ones are packaged so AI agents follow them consistently across every phase of development.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  DEFINE          PLAN           BUILD          VERIFY         REVIEW          SHIP</span></span>
<span class="line"><span> ┌──────┐      ┌──────┐      ┌──────┐      ┌──────┐      ┌──────┐      ┌──────┐</span></span>
<span class="line"><span> │ Idea │ ───▶ │ Spec │ ───▶ │ Code │ ───▶ │ Test │ ───▶ │  QA  │ ───▶ │  Go  │</span></span>
<span class="line"><span> │Refine│      │  PRD │      │ Impl │      │Debug │      │ Gate │      │ Live │</span></span>
<span class="line"><span> └──────┘      └──────┘      └──────┘      └──────┘      └──────┘      └──────┘</span></span>
<span class="line"><span>  /spec          /plan          /build        /test         /review       /ship</span></span></code></pre></div><hr><h2 id="commands" tabindex="-1">Commands <a class="header-anchor" href="#commands" aria-label="Permalink to &quot;Commands&quot;">​</a></h2><p>7 slash commands that map to the development lifecycle. Each one activates the right skills automatically.</p><table tabindex="0"><thead><tr><th>What you&#39;re doing</th><th>Command</th><th>Key principle</th></tr></thead><tbody><tr><td>Define what to build</td><td><code>/spec</code></td><td>Spec before code</td></tr><tr><td>Plan how to build it</td><td><code>/plan</code></td><td>Small, atomic tasks</td></tr><tr><td>Build incrementally</td><td><code>/build</code></td><td>One slice at a time</td></tr><tr><td>Prove it works</td><td><code>/test</code></td><td>Tests are proof</td></tr><tr><td>Review before merge</td><td><code>/review</code></td><td>Improve code health</td></tr><tr><td>Simplify the code</td><td><code>/code-simplify</code></td><td>Clarity over cleverness</td></tr><tr><td>Ship to production</td><td><code>/ship</code></td><td>Faster is safer</td></tr></tbody></table><p>Skills also activate automatically based on what you&#39;re doing — designing an API triggers <code>api-and-interface-design</code>, building UI triggers <code>frontend-ui-engineering</code>, and so on.</p><hr><h2 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h2><details><summary><b>Claude Code (recommended)</b></summary><p><strong>Marketplace install:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugin marketplace add addyosmani/agent-skills</span></span>
<span class="line"><span>/plugin install agent-skills@addy-agent-skills</span></span></code></pre></div><p><strong>Local / development:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/addyosmani/agent-skills.git</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --plugin-dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/agent-skills</span></span></code></pre></div></details><details><summary><b>Cursor</b></summary><p>Copy any <code>SKILL.md</code> into <code>.cursor/rules/</code>, or reference the full <code>skills/</code> directory. See <a href="./docs/cursor-setup.html">docs/cursor-setup.md</a>.</p></details><details><summary><b>Windsurf</b></summary><p>Add skill contents to your Windsurf rules configuration. See <a href="./docs/windsurf-setup.html">docs/windsurf-setup.md</a>.</p></details><details><summary><b>GitHub Copilot</b></summary><p>Use agent definitions from <code>agents/</code> as Copilot personas and skill content in <code>.github/copilot-instructions.md</code>. See <a href="./docs/copilot-setup.html">docs/copilot-setup.md</a>.</p></details><details><summary><b>Codex / Other Agents</b></summary><p>Skills are plain Markdown - they work with any agent that accepts system prompts or instruction files. See <a href="./docs/getting-started.html">docs/getting-started.md</a>.</p></details><hr><h2 id="all-19-skills" tabindex="-1">All 19 Skills <a class="header-anchor" href="#all-19-skills" aria-label="Permalink to &quot;All 19 Skills&quot;">​</a></h2><p>The commands above are the entry points. Under the hood, they activate these 19 skills — each one a structured workflow with steps, verification gates, and anti-rationalization tables. You can also reference any skill directly.</p><h3 id="define-clarify-what-to-build" tabindex="-1">Define - Clarify what to build <a class="header-anchor" href="#define-clarify-what-to-build" aria-label="Permalink to &quot;Define - Clarify what to build&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Skill</th><th>What It Does</th><th>Use When</th></tr></thead><tbody><tr><td><a href="./skills/idea-refine/SKILL.html">idea-refine</a></td><td>Structured divergent/convergent thinking to turn vague ideas into concrete proposals</td><td>You have a rough concept that needs exploration</td></tr><tr><td><a href="./skills/spec-driven-development/SKILL.html">spec-driven-development</a></td><td>Write a PRD covering objectives, commands, structure, code style, testing, and boundaries before any code</td><td>Starting a new project, feature, or significant change</td></tr></tbody></table><h3 id="plan-break-it-down" tabindex="-1">Plan - Break it down <a class="header-anchor" href="#plan-break-it-down" aria-label="Permalink to &quot;Plan - Break it down&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Skill</th><th>What It Does</th><th>Use When</th></tr></thead><tbody><tr><td><a href="./skills/planning-and-task-breakdown/SKILL.html">planning-and-task-breakdown</a></td><td>Decompose specs into small, verifiable tasks with acceptance criteria and dependency ordering</td><td>You have a spec and need implementable units</td></tr></tbody></table><h3 id="build-write-the-code" tabindex="-1">Build - Write the code <a class="header-anchor" href="#build-write-the-code" aria-label="Permalink to &quot;Build - Write the code&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Skill</th><th>What It Does</th><th>Use When</th></tr></thead><tbody><tr><td><a href="./skills/incremental-implementation/SKILL.html">incremental-implementation</a></td><td>Thin vertical slices - implement, test, verify, commit. Feature flags, safe defaults, rollback-friendly changes</td><td>Any change touching more than one file</td></tr><tr><td><a href="./skills/context-engineering/SKILL.html">context-engineering</a></td><td>Feed agents the right information at the right time - rules files, context packing, MCP integrations</td><td>Starting a session, switching tasks, or when output quality drops</td></tr><tr><td><a href="./skills/frontend-ui-engineering/SKILL.html">frontend-ui-engineering</a></td><td>Component architecture, design systems, state management, responsive design, WCAG 2.1 AA accessibility</td><td>Building or modifying user-facing interfaces</td></tr><tr><td><a href="./skills/api-and-interface-design/SKILL.html">api-and-interface-design</a></td><td>Contract-first design, Hyrum&#39;s Law, One-Version Rule, error semantics, boundary validation</td><td>Designing APIs, module boundaries, or public interfaces</td></tr></tbody></table><h3 id="verify-prove-it-works" tabindex="-1">Verify - Prove it works <a class="header-anchor" href="#verify-prove-it-works" aria-label="Permalink to &quot;Verify - Prove it works&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Skill</th><th>What It Does</th><th>Use When</th></tr></thead><tbody><tr><td><a href="./skills/test-driven-development/SKILL.html">test-driven-development</a></td><td>Red-Green-Refactor, test pyramid (80/15/5), test sizes, DAMP over DRY, Beyonce Rule, browser testing</td><td>Implementing logic, fixing bugs, or changing behavior</td></tr><tr><td><a href="./skills/browser-testing-with-devtools/SKILL.html">browser-testing-with-devtools</a></td><td>Chrome DevTools MCP for live runtime data - DOM inspection, console logs, network traces, performance profiling</td><td>Building or debugging anything that runs in a browser</td></tr><tr><td><a href="./skills/debugging-and-error-recovery/SKILL.html">debugging-and-error-recovery</a></td><td>Five-step triage: reproduce, localize, reduce, fix, guard. Stop-the-line rule, safe fallbacks</td><td>Tests fail, builds break, or behavior is unexpected</td></tr></tbody></table><h3 id="review-quality-gates-before-merge" tabindex="-1">Review - Quality gates before merge <a class="header-anchor" href="#review-quality-gates-before-merge" aria-label="Permalink to &quot;Review - Quality gates before merge&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Skill</th><th>What It Does</th><th>Use When</th></tr></thead><tbody><tr><td><a href="./skills/code-review-and-quality/SKILL.html">code-review-and-quality</a></td><td>Five-axis review, change sizing (~100 lines), severity labels (Nit/Optional/FYI), review speed norms, splitting strategies</td><td>Before merging any change</td></tr><tr><td><a href="./skills/code-simplification/SKILL.html">code-simplification</a></td><td>Chesterton&#39;s Fence, Rule of 500, reduce complexity while preserving exact behavior</td><td>Code works but is harder to read or maintain than it should be</td></tr><tr><td><a href="./skills/security-and-hardening/SKILL.html">security-and-hardening</a></td><td>OWASP Top 10 prevention, auth patterns, secrets management, dependency auditing, three-tier boundary system</td><td>Handling user input, auth, data storage, or external integrations</td></tr><tr><td><a href="./skills/performance-optimization/SKILL.html">performance-optimization</a></td><td>Measure-first approach - Core Web Vitals targets, profiling workflows, bundle analysis, anti-pattern detection</td><td>Performance requirements exist or you suspect regressions</td></tr></tbody></table><h3 id="ship-deploy-with-confidence" tabindex="-1">Ship - Deploy with confidence <a class="header-anchor" href="#ship-deploy-with-confidence" aria-label="Permalink to &quot;Ship - Deploy with confidence&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Skill</th><th>What It Does</th><th>Use When</th></tr></thead><tbody><tr><td><a href="./skills/git-workflow-and-versioning/SKILL.html">git-workflow-and-versioning</a></td><td>Trunk-based development, atomic commits, change sizing (~100 lines), the commit-as-save-point pattern</td><td>Making any code change (always)</td></tr><tr><td><a href="./skills/ci-cd-and-automation/SKILL.html">ci-cd-and-automation</a></td><td>Shift Left, Faster is Safer, feature flags, quality gate pipelines, failure feedback loops</td><td>Setting up or modifying build and deploy pipelines</td></tr><tr><td><a href="./skills/deprecation-and-migration/SKILL.html">deprecation-and-migration</a></td><td>Code-as-liability mindset, compulsory vs advisory deprecation, migration patterns, zombie code removal</td><td>Removing old systems, migrating users, or sunsetting features</td></tr><tr><td><a href="./skills/documentation-and-adrs/SKILL.html">documentation-and-adrs</a></td><td>Architecture Decision Records, API docs, inline documentation standards - document the <em>why</em></td><td>Making architectural decisions, changing APIs, or shipping features</td></tr><tr><td><a href="./skills/shipping-and-launch/SKILL.html">shipping-and-launch</a></td><td>Pre-launch checklists, feature flag lifecycle, staged rollouts, rollback procedures, monitoring setup</td><td>Preparing to deploy to production</td></tr></tbody></table><hr><h2 id="agent-personas" tabindex="-1">Agent Personas <a class="header-anchor" href="#agent-personas" aria-label="Permalink to &quot;Agent Personas&quot;">​</a></h2><p>Pre-configured specialist personas for targeted reviews:</p><table tabindex="0"><thead><tr><th>Agent</th><th>Role</th><th>Perspective</th></tr></thead><tbody><tr><td><a href="./agents/code-reviewer.html">code-reviewer</a></td><td>Senior Staff Engineer</td><td>Five-axis code review with &quot;would a staff engineer approve this?&quot; standard</td></tr><tr><td><a href="./agents/test-engineer.html">test-engineer</a></td><td>QA Specialist</td><td>Test strategy, coverage analysis, and the Prove-It pattern</td></tr><tr><td><a href="./agents/security-auditor.html">security-auditor</a></td><td>Security Engineer</td><td>Vulnerability detection, threat modeling, OWASP assessment</td></tr></tbody></table><hr><h2 id="reference-checklists" tabindex="-1">Reference Checklists <a class="header-anchor" href="#reference-checklists" aria-label="Permalink to &quot;Reference Checklists&quot;">​</a></h2><p>Quick-reference material that skills pull in when needed:</p><table tabindex="0"><thead><tr><th>Reference</th><th>Covers</th></tr></thead><tbody><tr><td><a href="./references/testing-patterns.html">testing-patterns.md</a></td><td>Test structure, naming, mocking, React/API/E2E examples, anti-patterns</td></tr><tr><td><a href="./references/security-checklist.html">security-checklist.md</a></td><td>Pre-commit checks, auth, input validation, headers, CORS, OWASP Top 10</td></tr><tr><td><a href="./references/performance-checklist.html">performance-checklist.md</a></td><td>Core Web Vitals targets, frontend/backend checklists, measurement commands</td></tr><tr><td><a href="./references/accessibility-checklist.html">accessibility-checklist.md</a></td><td>Keyboard nav, screen readers, visual design, ARIA, testing tools</td></tr></tbody></table><hr><h2 id="how-skills-work" tabindex="-1">How Skills Work <a class="header-anchor" href="#how-skills-work" aria-label="Permalink to &quot;How Skills Work&quot;">​</a></h2><p>Every skill follows a consistent anatomy:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  SKILL.md                                   │</span></span>
<span class="line"><span>│                                             │</span></span>
<span class="line"><span>│  ┌─ Frontmatter ─────────────────────────┐  │</span></span>
<span class="line"><span>│  │ name: lowercase-hyphen-name           │  │</span></span>
<span class="line"><span>│  │ description: Use when [trigger]       │  │</span></span>
<span class="line"><span>│  └───────────────────────────────────────┘  │</span></span>
<span class="line"><span>│                                             │</span></span>
<span class="line"><span>│  Overview         → What this skill does    │</span></span>
<span class="line"><span>│  When to Use      → Triggering conditions   │</span></span>
<span class="line"><span>│  Process          → Step-by-step workflow   │</span></span>
<span class="line"><span>│  Rationalizations → Excuses + rebuttals     │</span></span>
<span class="line"><span>│  Red Flags        → Signs something&#39;s wrong │</span></span>
<span class="line"><span>│  Verification     → Evidence requirements   │</span></span>
<span class="line"><span>└─────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>Key design choices:</strong></p><ul><li><strong>Process, not prose.</strong> Skills are workflows agents follow, not reference docs they read. Each has steps, checkpoints, and exit criteria.</li><li><strong>Anti-rationalization.</strong> Every skill includes a table of common excuses agents use to skip steps (e.g., &quot;I&#39;ll add tests later&quot;) with documented counter-arguments.</li><li><strong>Verification is non-negotiable.</strong> Every skill ends with evidence requirements - tests passing, build output, runtime data. &quot;Seems right&quot; is never sufficient.</li><li><strong>Progressive disclosure.</strong> The <code>SKILL.md</code> is the entry point. Supporting references load only when needed, keeping token usage minimal.</li></ul><hr><h2 id="project-structure" tabindex="-1">Project Structure <a class="header-anchor" href="#project-structure" aria-label="Permalink to &quot;Project Structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>agent-skills/</span></span>
<span class="line"><span>├── skills/                            # 19 core skills (SKILL.md per directory)</span></span>
<span class="line"><span>│   ├── idea-refine/                   #   Define</span></span>
<span class="line"><span>│   ├── spec-driven-development/       #   Define</span></span>
<span class="line"><span>│   ├── planning-and-task-breakdown/   #   Plan</span></span>
<span class="line"><span>│   ├── incremental-implementation/    #   Build</span></span>
<span class="line"><span>│   ├── context-engineering/           #   Build</span></span>
<span class="line"><span>│   ├── frontend-ui-engineering/       #   Build</span></span>
<span class="line"><span>│   ├── api-and-interface-design/      #   Build</span></span>
<span class="line"><span>│   ├── test-driven-development/       #   Verify</span></span>
<span class="line"><span>│   ├── browser-testing-with-devtools/ #   Verify</span></span>
<span class="line"><span>│   ├── debugging-and-error-recovery/  #   Verify</span></span>
<span class="line"><span>│   ├── code-review-and-quality/       #   Review</span></span>
<span class="line"><span>│   ├── code-simplification/          #   Review</span></span>
<span class="line"><span>│   ├── security-and-hardening/        #   Review</span></span>
<span class="line"><span>│   ├── performance-optimization/      #   Review</span></span>
<span class="line"><span>│   ├── git-workflow-and-versioning/   #   Ship</span></span>
<span class="line"><span>│   ├── ci-cd-and-automation/          #   Ship</span></span>
<span class="line"><span>│   ├── deprecation-and-migration/     #   Ship</span></span>
<span class="line"><span>│   ├── documentation-and-adrs/        #   Ship</span></span>
<span class="line"><span>│   ├── shipping-and-launch/           #   Ship</span></span>
<span class="line"><span>│   └── using-agent-skills/            #   Meta: how to use this pack</span></span>
<span class="line"><span>├── agents/                            # 3 specialist personas</span></span>
<span class="line"><span>├── references/                        # 4 supplementary checklists</span></span>
<span class="line"><span>├── hooks/                             # Session lifecycle hooks</span></span>
<span class="line"><span>├── .claude/commands/                  # 7 slash commands</span></span>
<span class="line"><span>└── docs/                              # Setup guides per tool</span></span></code></pre></div><hr><h2 id="why-agent-skills" tabindex="-1">Why Agent Skills? <a class="header-anchor" href="#why-agent-skills" aria-label="Permalink to &quot;Why Agent Skills?&quot;">​</a></h2><p>AI coding agents default to the shortest path - which often means skipping specs, tests, security reviews, and the practices that make software reliable. Agent Skills gives agents structured workflows that enforce the same discipline senior engineers bring to production code.</p><p>Each skill encodes hard-won engineering judgment: <em>when</em> to write a spec, <em>what</em> to test, <em>how</em> to review, and <em>when</em> to ship. These aren&#39;t generic prompts - they&#39;re the kind of opinionated, process-driven workflows that separate production-quality work from prototype-quality work.</p><p>Skills bake in best practices from Google&#39;s engineering culture — including concepts from <a href="https://abseil.io/resources/swe-book" target="_blank" rel="noreferrer">Software Engineering at Google</a> and Google&#39;s <a href="https://google.github.io/eng-practices/" target="_blank" rel="noreferrer">engineering practices guide</a>. You&#39;ll find Hyrum&#39;s Law in API design, the Beyonce Rule and test pyramid in testing, change sizing and review speed norms in code review, Chesterton&#39;s Fence in simplification, trunk-based development in git workflow, Shift Left and feature flags in CI/CD, and a dedicated deprecation skill treating code as a liability. These aren&#39;t abstract principles — they&#39;re embedded directly into the step-by-step workflows agents follow.</p><hr><h2 id="contributing" tabindex="-1">Contributing <a class="header-anchor" href="#contributing" aria-label="Permalink to &quot;Contributing&quot;">​</a></h2><p>Skills should be <strong>specific</strong> (actionable steps, not vague advice), <strong>verifiable</strong> (clear exit criteria with evidence requirements), <strong>battle-tested</strong> (based on real workflows), and <strong>minimal</strong> (only what&#39;s needed to guide the agent).</p><p>See <a href="./docs/skill-anatomy.html">docs/skill-anatomy.md</a> for the format specification and <a href="./CONTRIBUTING.html">CONTRIBUTING.md</a> for guidelines.</p><hr><h2 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to &quot;License&quot;">​</a></h2><p>MIT - use these skills in your projects, teams, and tools.</p>`,60)])])}const u=t(i,[["render",r]]);export{g as __pageData,u as default};
